import{_ as a,o,c as t,a2 as n}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"[SECURITY] F-05.3 — Autenticación Externa y Protección de Rutas","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-05.3_autenticacion_admin.md","filePath":"backlog/F-05.3_autenticacion_admin.md","lastUpdated":null}'),r={name:"backlog/F-05.3_autenticacion_admin.md"};function i(d,e,c,s,l,u){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="security-f-05-3-—-autenticacion-externa-y-proteccion-de-rutas" tabindex="-1">[SECURITY] F-05.3 — Autenticación Externa y Protección de Rutas <a class="header-anchor" href="#security-f-05-3-—-autenticacion-externa-y-proteccion-de-rutas" aria-label="Permalink to &quot;[SECURITY] F-05.3 — Autenticación Externa y Protección de Rutas&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-05 — Infraestructura y Conectividad</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Security</code><strong>Impacta en:</strong> Equipo Backend (Laravel)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-00.1_setup_laravel_livewire.html">F-00.1</a></td><td>Base Laravel instalada; <code>bootstrap/app.php</code> donde registrar el middleware</td></tr><tr><td><a href="./F-05.5_usuarios_mock_session.html">F-05.5</a></td><td>Tabla <code>users</code> y <code>UserSeeder</code> disponibles para el mock de sesión</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero que el panel valide mi sesión activa proveniente del sistema de autenticación externo Para acceder al panel sin necesidad de un formulario de login propio dentro de esta aplicación</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Acceso con sesión válida):</strong> Dado que llego al panel con una cookie de sesión válida del sistema externo, cuando el middleware de autenticación la valida, entonces accedo directamente al dashboard sin formulario de login.</li><li>[ ] <strong>Escenario 2 (Acceso sin sesión):</strong> Dado que un usuario sin sesión activa intenta acceder a cualquier ruta del panel, cuando el middleware detecta que no hay sesión, entonces es redirigido al portal externo de login (URL configurable en <code>.env</code>).</li><li>[ ] <strong>Escenario 3 (Rutas protegidas):</strong> Dado que todas las rutas web están dentro del grupo <code>middleware:auth</code>, cuando cualquier petición no autenticada llega, entonces Laravel la redirige automáticamente via <code>Authenticate</code> middleware.</li><li>[ ] <strong>Escenario 4 (Logout):</strong> Dado que el admin pulsa &quot;Cerrar sesión&quot;, cuando se ejecuta la acción (ruta <code>POST /logout</code>), entonces la sesión local de Laravel se invalida y se redirige al portal externo.</li><li>[ ] <strong>Escenario 5 (Mock en desarrollo):</strong> Dado que estamos en entorno <code>APP_ENV=local</code>, cuando el middleware <code>AuthMock</code> está activo, entonces el usuario se carga directamente desde la tabla <code>users</code> sin validar sesión externa. Permite desarrollo sin integración con el auth externo.</li><li>[ ] <strong>Requisito Técnico:</strong> Middleware <code>AuthGateway</code> en <code>app/Http/Middleware/</code>. Lógica: si <code>APP_ENV=local</code> → usa <code>AuthMock</code> (carga <code>User::find(1)</code>); si <code>production</code> → valida token/cookie del sistema externo. Todas las rutas web usan <code>middleware:auth</code>. Registrar en <code>bootstrap/app.php</code>.</li></ul><hr><p><strong>MoSCoW:</strong> <code>MUST</code><strong>Sprint:</strong> Sprint 0</p><p><strong>Notas:</strong></p><ul><li><strong>Sin pantalla de login en este panel.</strong> El wireframe del proyecto tiene la pantalla de login tachada expresamente.</li><li>El sistema externo de autenticación es una API separada fuera del alcance de este proyecto.</li><li>La integración real con el auth externo se documenta en <code>.env.example</code> (variable <code>AUTH_EXTERNAL_URL</code>).</li><li>En desarrollo: <code>php artisan db:seed --seeder=UserSeeder</code> crea el usuario mock con ID=1.</li></ul>',16)])])}const m=a(r,[["render",i]]);export{g as __pageData,m as default};
